def renew(plan, coupon, gateway):
 subtotal=plan.monthly_cents
 discount=coupon.discount(subtotal) if coupon else 0
 charge=max(0,subtotal-discount)
 return gateway.charge(charge, idempotency_key=plan.subscription_id)

class Coupon:
 def __init__(self,percent=None,fixed_cents=None): self.percent=percent; self.fixed_cents=fixed_cents
 def discount(self,total): return self.fixed_cents or total*self.percent//100

